import{_ as a}from"./MamnzQeh.js";import{_ as o,c as s,b as r,e as n,o as d}from"./Co4Qz217.js";import"./0Mx8XfZ_.js";const i={name:"About"},c={class:"root flex flex-col h-screen"};function l(p,t,u,m,y,h){const e=a;return d(),s("div",c,[r(e,{"is-about":""}),t[0]||(t[0]=n('<div class="p-4 h-full" data-v-6e75528d><h1 class="text-title sm:pr-64" data-v-6e75528d> Triton - GDSC VIT&#39;s pastebin and URL shortener </h1><p class="text-body sm:pr-64" data-v-6e75528d> Sharing short code samples, logs or links is now easier than ever! </p><br data-v-6e75528d><h1 class="text-title sm:pr-64" data-v-6e75528d>Basics</h1><p class="text-body sm:pr-64" data-v-6e75528d> The easiest way to use triton, is from inside your browser. Type or paste your content into the text area on the homepage, save it, and copy the link. You can now share this link with whoever you want. </p><p class="text-body sm:pr-64" data-v-6e75528d> If you want to create a short url from a link, simply paste the link in the text field. You can now copy the resulting link and it will automatically redirect everyone. </p><br data-v-6e75528d><h1 class="text-title sm:pr-64" data-v-6e75528d>Editing</h1><p class="text-body sm:pr-64" data-v-6e75528d> You can edit your documents by clicking the edit button </p><p class="text-body sm:pr-64" data-v-6e75528d> When you create your first document we will automatically create an (anonymous) account for you, so you will be able to edit your documents for as long as you keep our cookie. If you want a more permanent way to keep your pastes and edit them from multiple devices you can create an account. Pastes which you created before signing up will be automatically transferred to your account. </p><br data-v-6e75528d><h1 class="text-title sm:pr-64" data-v-6e75528d>Markdown support</h1><p class="text-body sm:pr-64" data-v-6e75528d> We support markdown documents formatting in the CommonMark spec. Append &quot;.md&quot; to the end of the url to render any paste as markdown. </p><br data-v-6e75528d><h1 class="text-title sm:pr-64" data-v-6e75528d>Analytics</h1><p class="text-body sm:pr-64" data-v-6e75528d> We support per-page analytics using a privacy-friendly analytics provider, <a class="underline text-amber cursor-pointer" href="https://simpleanalytics.com" data-v-6e75528d>Simple Analytics</a></p><br data-v-6e75528d><h1 class="text-title sm:pr-64" data-v-6e75528d>Document lifetime</h1><p class="text-body sm:pr-64" data-v-6e75528d> There is no explicit expiration time for documents on triton. Documents may however be removed at any time without notice. </p><br data-v-6e75528d><h1 class="text-title sm:pr-64" data-v-6e75528d>Open source</h1><p class="text-body sm:pr-64" data-v-6e75528d> Triton is fully open source and built on open source technology. All sources can be found on <a class="underline text-amber cursor-pointer" href="https://github.com/GDGVIT/triton-web" data-v-6e75528d>GitHub</a>. You can easily deploy it yourself wherever you want. </p></div>',1))])}const x=o(i,[["render",l],["__scopeId","data-v-6e75528d"]]);export{x as default};
